    public java.util.concurrent.CompletableFuture<Object> keepAliveListenKey(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object listenKey = this.safeString(this.options, "listenKey");
            if (Helpers.isTrue(Helpers.isEqual(listenKey, null)))
            {
                // A network error happened: we can't renew a listen key that does not exist.
                return null;
            }
            try
            {
                (this.v1PrivatePutApiUsersSocketListenKeysListenKey(new java.util.HashMap<String, Object>() {{
                    put( "listenKey", listenKey );
                }})).join(); // extend the expiry
            } catch(Exception error)
            {
                Object url = Helpers.add(Helpers.add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "private"), "?listenKey="), listenKey);
                Client client = this.client(url);
                Object messageHashes = new java.util.ArrayList<Object>(((java.util.Map)client.futures).keySet());
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(messageHashes)); j++)
                {
                    Object messageHash = Helpers.GetValue(messageHashes, j);
                    client.reject(error, messageHash);
                }
                Helpers.addElementToObject(this.options, "listenKey", null);
                Helpers.addElementToObject(this.options, "lastAuthenticatedTime", 0);
                return null;
            }
            // whether or not to schedule another listenKey keepAlive request
            Object listenKeyRefreshRate = this.safeInteger(this.options, "listenKeyRefreshRate", 3540000);
            this.spawn(() -> { try { Thread.sleep(((Number)listenKeyRefreshRate).longValue()); this.keepAliveListenKey(parameters); } catch(Exception _e) {} });
            return null;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object time = this.milliseconds();
            Object lastAuthenticatedTime = this.safeInteger(this.options, "lastAuthenticatedTime", 0);
            Object listenKeyRefreshRate = this.safeInteger(this.options, "listenKeyRefreshRate", 3540000); // 1 hour
            if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.subtract(time, lastAuthenticatedTime), listenKeyRefreshRate)))
            {
                Object response = (this.v1PrivatePostApiUsersSocketListenKeys()).join();
                Helpers.addElementToObject(this.options, "listenKey", this.safeString(response, "listenKey"));
                Helpers.addElementToObject(this.options, "lastAuthenticatedTime", time);
                this.spawn(() -> { try { Thread.sleep(((Number)listenKeyRefreshRate).longValue()); this.keepAliveListenKey(parameters); } catch(Exception _e) {} });
            }
            return null;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

